  /* ── RUEDA DE PRENSA — preguntas y respuestas ── */
  'press.q0': {es:'«¿Dejaréis la portería a cero en este encuentro?»', en:'"Will you keep a clean sheet in this match?"', pt:'"Will you keep a clean sheet in this match?"', fr:'"Will you keep a clean sheet in this match?"', de:'"Will you keep a clean sheet in this match?"', it:'"Will you keep a clean sheet in this match?"'},
  'press.q0a0.text': {es:'«Sí, vamos a por la portería a cero.»', en:'"Yes, we\'re going for the clean sheet."', pt:'"Yes, we\'re going for the clean sheet."', fr:'"Yes, we\'re going for the clean sheet."', de:'"Yes, we\'re going for the clean sheet."', it:'"Yes, we\'re going for the clean sheet."'},
  'press.q0a0.label': {es:'Confiado', en:'Confident', pt:'Confident', fr:'Confident', de:'Confident', it:'Confident'},
  'press.q0a1.text': {es:'«Es difícil de prometer, ya veremos.»', en:'"It\'s hard to promise, we\'ll see."', pt:'"It\'s hard to promise, we\'ll see."', fr:'"It\'s hard to promise, we\'ll see."', de:'"It\'s hard to promise, we\'ll see."', it:'"It\'s hard to promise, we\'ll see."'},
  'press.q0a1.label': {es:'Prudente', en:'Cautious', pt:'Cautious', fr:'Cautious', de:'Cautious', it:'Cautious'},
  'press.q0a2.text': {es:'«Lo veo complicado, encajaremos.»', en:'"I think we\'ll concede, it\'s complicated."', pt:'"I think we\'ll concede, it\'s complicated."', fr:'"I think we\'ll concede, it\'s complicated."', de:'"I think we\'ll concede, it\'s complicated."', it:'"I think we\'ll concede, it\'s complicated."'},
