  'press.q1': {es:'«¿Vais a ganar por tres goles o más?»', en:'"Are you going to win by three goals or more?"', pt:'"Are you going to win by three goals or more?"', fr:'"Are you going to win by three goals or more?"', de:'"Are you going to win by three goals or more?"', it:'"Are you going to win by three goals or more?"'},
  'press.q1a0.text': {es:'«Sí, vamos a golear.»', en:'"Yes, we\'re going to score plenty."', pt:'"Yes, we\'re going to score plenty."', fr:'"Yes, we\'re going to score plenty."', de:'"Yes, we\'re going to score plenty."', it:'"Yes, we\'re going to score plenty."'},
  'press.q1a0.label': {es:'Ambicioso', en:'Ambitious', pt:'Ambitious', fr:'Ambitious', de:'Ambitious', it:'Ambitious'},
  'press.q1a1.text': {es:'«No me atrevo a predecir el marcador.»', en:'"I wouldn\'t dare predict the scoreline."', pt:'"I wouldn\'t dare predict the scoreline."', fr:'"I wouldn\'t dare predict the scoreline."', de:'"I wouldn\'t dare predict the scoreline."', it:'"I wouldn\'t dare predict the scoreline."'},
  'press.q1a1.label': {es:'Cauto', en:'Wary', pt:'Wary', fr:'Wary', de:'Wary', it:'Wary'},
  'press.q1a2.text': {es:'«No, será un partido ajustado.»', en:'"No, it\'ll be a tight game."', pt:'"No, it\'ll be a tight game."', fr:'"No, it\'ll be a tight game."', de:'"No, it\'ll be a tight game."', it:'"No, it\'ll be a tight game."'},
  'press.q1a2.label': {es:'Realista', en:'Realistic', pt:'Realistic', fr:'Realistic', de:'Realistic', it:'Realistic'},

  'press.q2': {es:'«Lleváis varios partidos viendo tarjetas. ¿Seguiréis acumulando en este encuentro?»', en:'"You\'ve been picking up cards lately. Will you keep collecting them in this match?"', pt:'"You\'ve been picking up cards lately. Will you keep collecting them in this match?"', fr:'"You\'ve been picking up cards lately. Will you keep collecting them in this match?"', de:'"You\'ve been picking up cards lately. Will you keep collecting them in this match?"', it:'"You\'ve been picking up cards lately. Will you keep collecting them in this match?"'},
  'press.q2a0.text': {es:'«No, vamos a jugar limpio esta vez.»', en:'"No, we\'re going to play clean this time."', pt:'"No, we\'re going to play clean this time."', fr:'"No, we\'re going to play clean this time."', de:'"No, we\'re going to play clean this time."', it:'"No, we\'re going to play clean this time."'},
  'press.q2a0.label': {es:'Comprometido', en:'Committed', pt:'Committed', fr:'Committed', de:'Committed', it:'Committed'},
  'press.q2a1.text': {es:'«No puedo controlar lo que pite el árbitro.»', en:'"I can\'t control what the referee calls."', pt:'"I can\'t control what the referee calls."', fr:'"I can\'t control what the referee calls."', de:'"I can\'t control what the referee calls."', it:'"I can\'t control what the referee calls."'},
  'press.q2a1.label': {es:'Evasivo', en:'Evasive', pt:'Evasive', fr:'Evasive', de:'Evasive', it:'Evasive'},
  'press.q2a2.text': {es:'«Es probable, el rival nos hará cometer faltas.»', en:'"Probably — the opponent will force us into fouls."', pt:'"Probably — the opponent will force us into fouls."', fr:'"Probably — the opponent will force us into fouls."', de:'"Probably — the opponent will force us into fouls."', it:'"Probably — the opponent will force us into fouls."'},
  'press.q2a2.label': {es:'Sincero', en:'Honest', pt:'Honest', fr:'Honest', de:'Honest', it:'Honest'},

  'press.q3': {es:'«¿Marcaréis en la primera mitad?»', en:'"Will you score in the first half?"', pt:'"Will you score in the first half?"', fr:'"Will you score in the first half?"', de:'"Will you score in the first half?"', it:'"Will you score in the first half?"'},
  'press.q3a0.text': {es:'«Sí, saldremos a por todas desde el inicio.»', en:'"Yes, we\'ll go all out from the start."', pt:'"Yes, we\'ll go all out from the start."', fr:'"Yes, we\'ll go all out from the start."', de:'"Yes, we\'ll go all out from the start."', it:'"Yes, we\'ll go all out from the start."'},
  'press.q3a0.label': {es:'Decidido', en:'Determined', pt:'Determined', fr:'Determined', de:'Determined', it:'Determined'},
  'press.q3a1.text': {es:'«El plan de partido lo decide el míster.»', en:'"The game plan is the manager\'s call."', pt:'"The game plan is the manager\'s call."', fr:'"The game plan is the manager\'s call."', de:'"The game plan is the manager\'s call."', it:'"The game plan is the manager\'s call."'},
  'press.q3a1.label': {es:'Diplomático', en:'Diplomatic', pt:'Diplomatic', fr:'Diplomatic', de:'Diplomatic', it:'Diplomatic'},
  'press.q3a2.text': {es:'«Seremos pacientes, no hay prisa por marcar.»', en:'"We\'ll be patient — no rush to score."', pt:'"We\'ll be patient — no rush to score."', fr:'"We\'ll be patient — no rush to score."', de:'"We\'ll be patient — no rush to score."', it:'"We\'ll be patient — no rush to score."'},
  'press.q3a2.label': {es:'Paciente', en:'Patient', pt:'Patient', fr:'Patient', de:'Patient', it:'Patient'},

  'press.q4': {es:'«¿Va a generar más ocasiones el rival que vosotros?»', en:'"Will the opponent create more chances than you?"', pt:'"Will the opponent create more chances than you?"', fr:'"Will the opponent create more chances than you?"', de:'"Will the opponent create more chances than you?"', it:'"Will the opponent create more chances than you?"'},
  'press.q4a0.text': {es:'«No, vamos a dominar nosotros el partido.»', en:'"No, we\'re going to control the game."', pt:'"No, we\'re going to control the game."', fr:'"No, we\'re going to control the game."', de:'"No, we\'re going to control the game."', it:'"No, we\'re going to control the game."'},
  'press.q4a0.label': {es:'Dominante', en:'Dominant', pt:'Dominant', fr:'Dominant', de:'Dominant', it:'Dominant'},
  'press.q4a1.text': {es:'«Cada partido es distinto, lo veremos en el campo.»', en:'"Every match is different — we\'ll see on the pitch."', pt:'"Every match is different — we\'ll see on the pitch."', fr:'"Every match is different — we\'ll see on the pitch."', de:'"Every match is different — we\'ll see on the pitch."', it:'"Every match is different — we\'ll see on the pitch."'},
  'press.q4a1.label': {es:'Flexible', en:'Flexible', pt:'Flexible', fr:'Flexible', de:'Flexible', it:'Flexible'},
  'press.q4a2.text': {es:'«Es un rival fuerte, nos costará contenerlo.»', en:'"They\'re a strong side — it won\'t be easy to contain them."', pt:'"They\'re a strong side — it won\'t be easy to contain them."', fr:'"They\'re a strong side — it won\'t be easy to contain them."', de:'"They\'re a strong side — it won\'t be easy to contain them."', it:'"They\'re a strong side — it won\'t be easy to contain them."'},
  'press.q4a2.label': {es:'Respetuoso', en:'Respectful', pt:'Respectful', fr:'Respectful', de:'Respectful', it:'Respectful'},

