  'press.q5a0.label': {es:'Seguro', en:'Confident', pt:'Confident', fr:'Confident', de:'Confident', it:'Confident'},
  'press.q5a1.text': {es:'«Lo importante es resolverlo, como sea.»', en:'"The important thing is to get it done, however it takes."', pt:'"The important thing is to get it done, however it takes."', fr:'"The important thing is to get it done, however it takes."', de:'"The important thing is to get it done, however it takes."', it:'"The important thing is to get it done, however it takes."'},
  'press.q5a1.label': {es:'Pragmático', en:'Pragmatic', pt:'Pragmatic', fr:'Pragmatic', de:'Pragmatic', it:'Pragmatic'},
  'press.q5a2.text': {es:'«Puede decidirse en los detalles, incluso en penaltis.»', en:'"It could come down to the fine margins — even penalties."', pt:'"It could come down to the fine margins — even penalties."', fr:'"It could come down to the fine margins — even penalties."', de:'"It could come down to the fine margins — even penalties."', it:'"It could come down to the fine margins — even penalties."'},
