  'press.q6': {es:'«¿Vais a marcar más de un gol en este partido?»', en:'"Are you going to score more than one goal in this match?"', pt:'"Are you going to score more than one goal in this match?"', fr:'"Are you going to score more than one goal in this match?"', de:'"Are you going to score more than one goal in this match?"', it:'"Are you going to score more than one goal in this match?"'},
  'press.q6a0.text': {es:'«Sí, tenemos gol en las botas.»', en:'"Yes, we have goals in our boots."', pt:'"Yes, we have goals in our boots."', fr:'"Yes, we have goals in our boots."', de:'"Yes, we have goals in our boots."', it:'"Yes, we have goals in our boots."'},
