  'press.q6a1.text': {es:'«Con uno nos conformamos si hace falta.»', en:'"One goal is enough if it comes to it."', pt:'"One goal is enough if it comes to it."', fr:'"One goal is enough if it comes to it."', de:'"One goal is enough if it comes to it."', it:'"One goal is enough if it comes to it."'},
  'press.q6a1.label': {es:'Pragmático', en:'Pragmatic', pt:'Pragmatic', fr:'Pragmatic', de:'Pragmatic', it:'Pragmatic'},
  'press.q6a2.text': {es:'«Va a costarnos encontrar el gol hoy.»', en:'"It\'s going to be hard to find the net today."', pt:'"It\'s going to be hard to find the net today."', fr:'"It\'s going to be hard to find the net today."', de:'"It\'s going to be hard to find the net today."', it:'"It\'s going to be hard to find the net today."'},
