  'press.q7a0.text': {es:'«No, vamos a estar sólidos atrás.»', en:'"No, we\'re going to be solid at the back."', pt:'"No, we\'re going to be solid at the back."', fr:'"No, we\'re going to be solid at the back."', de:'"No, we\'re going to be solid at the back."', it:'"No, we\'re going to be solid at the back."'},
