  'press.q8a0.text': {es:'«No, vamos a buscar la victoria hasta el final.»', en:'"No, we\'ll chase the win until the final whistle."', pt:'"No, we\'ll chase the win until the final whistle."', fr:'"No, we\'ll chase the win until the final whistle."', de:'"No, we\'ll chase the win until the final whistle."', it:'"No, we\'ll chase the win until the final whistle."'},
