  'press.q9a0.text': {es:'«Sí, va a estar fino delante de la portería.»', en:'"Yes, he\'ll be sharp in front of goal."', pt:'"Yes, he\'ll be sharp in front of goal."', fr:'"Yes, he\'ll be sharp in front of goal."', de:'"Yes, he\'ll be sharp in front of goal."', it:'"Yes, he\'ll be sharp in front of goal."'},
