  'press.q11a0.text': {es:'«Sí, esto va a ser ida y vuelta.»', en:'"Yes, it\'s going to be end to end."', pt:'"Yes, it\'s going to be end to end."', fr:'"Yes, it\'s going to be end to end."', de:'"Yes, it\'s going to be end to end."', it:'"Yes, it\'s going to be end to end."'},
