  /* ── TIPS (¿Sabías qué...?) ── */
  'tips.0': {es:'💡 Regístrate para guardar tu progreso y acceder a contenido exclusivo.', en:'💡 Register to save your progress and access exclusive content.', pt:'💡 Registre-se para salvar seu progresso e acessar conteúdo exclusivo.', fr:'💡 Inscrivez-vous pour sauvegarder votre progression et accéder au contenu exclusif.', de:'💡 Registriere dich, um deinen Fortschritt zu speichern und auf exklusive Inhalte zuzugreifen.', it:'💡 Registrati per salvare i tuoi progressi e accedere ai contenuti esclusivi.'},
  'tips.1': {es:'💡 Un jugador cansado rendirá peor en el campo, controla su resistencia.', en:'💡 A tired player will perform worse on the pitch — keep an eye on their stamina.', pt:'💡 Um jogador cansado renderá menos em campo — controle sua resistência.', fr:'💡 Un joueur fatigué sera moins performant sur le terrain — surveillez son endurance.', de:'💡 Ein müder Spieler wird auf dem Platz schlechter — behalte seine Ausdauer im Auge.', it:'💡 Un giocatore stanco rende meno in campo — controlla la sua resistenza.'},
