  /* ── CÓMO JUGAR — pasos ── */
  'howto.step1': {
    es:'Elige tu <strong>formación</strong> (queda fija todo el torneo) y arma tu once: <strong>SELECCIONAR JUGADOR</strong> o <strong>EQUIPO RÁPIDO</strong>. Coloca cada jugador en su <strong>posición ★</strong> para el 100% de rendimiento.',
    en:'Choose your <strong>formation</strong> (locked for the whole tournament) and build your eleven: <strong>SELECT PLAYER</strong> or <strong>QUICK TEAM</strong>. Place each player in their <strong>★ position</strong> for 100% performance.',
    pt:'Escolha sua <strong>formação</strong> (fixa para todo o torneio) e monte seu time: <strong>SELECIONAR JOGADOR</strong> ou <strong>TIME RÁPIDO</strong>. Coloque cada jogador em sua <strong>posição ★</strong> para 100% de rendimento.',
    fr:'Choisissez votre <strong>formation</strong> (fixée pour tout le tournoi) et composez votre onze : <strong>CHOISIR UN JOUEUR</strong> ou <strong>ÉQUIPE RAPIDE</strong>. Placez chaque joueur à son <strong>poste ★</strong> pour 100% de rendement.',
    de:'Wähle deine <strong>Formation</strong> (für das gesamte Turnier festgelegt) und stelle deine Elf zusammen: <strong>SPIELER WÄHLEN</strong> oder <strong>SCHNELLES TEAM</strong>. Platziere jeden Spieler auf seiner <strong>★-Position</strong> für 100% Leistung.',
    it:'Scegli la tua <strong>formazione</strong> (fissa per tutto il torneo) e componi l\'undici: <strong>SELEZIONA GIOCATORE</strong> o <strong>SQUADRA RAPIDA</strong>. Posiziona ogni giocatore nella sua <strong>posizione ★</strong> per il 100% di rendimento.'
  },
  'howto.step2': {
    es:'<strong>Grupos → Octavos → Cuartos → Semis → Final.</strong> Antes de cada partido: rueda de prensa (predicción → moral) y elige una <strong>estrategia</strong> que contrarreste al rival.',
    en:'<strong>Groups → Round of 16 → Quarter-finals → Semis → Final.</strong> Before each match: press conference (prediction → morale) and pick a <strong>strategy</strong> to counter your opponent.',
    pt:'<strong>Grupos → Oitavas → Quartas → Semis → Final.</strong> Antes de cada jogo: coletiva de imprensa (previsão → moral) e escolha uma <strong>estratégia</strong> que contrarie o rival.',
    fr:'<strong>Groupes → Huitièmes → Quarts → Demis → Finale.</strong> Avant chaque match : conférence de presse (prédiction → moral) et choisissez une <strong>stratégie</strong> pour contrer l\'adversaire.',
    de:'<strong>Gruppen → Achtelfinale → Viertelfinale → Halbfinale → Finale.</strong> Vor jedem Spiel: Pressekonferenz (Vorhersage → Moral) und wähle eine <strong>Strategie</strong>, um den Gegner zu kontern.',
    it:'<strong>Gironi → Ottavi → Quarti → Semifinali → Finale.</strong> Prima di ogni partita: conferenza stampa (previsione → morale) e scegli una <strong>strategia</strong> per contrastare il rivale.'
  },
  'howto.step3': {
    es:'Hasta <strong>2 cambios 🪑</strong> por partido (ampliables con mejoras). Vigila lesiones ✚, sanciones 🚫 y la barra de <strong>Resistencia</strong> — descansa en el banquillo para recuperarla.',
    en:'Up to <strong>2 substitutions 🪑</strong> per match (upgradeable). Watch for injuries ✚, suspensions 🚫 and the <strong>Stamina</strong> bar — rest players on the bench to recover it.',
    pt:'Até <strong>2 substituições 🪑</strong> por jogo (melhoráveis). Fique atento a lesões ✚, suspensões 🚫 e à barra de <strong>Resistência</strong> — descanse no banco para recuperá-la.',
    fr:'Jusqu\'à <strong>2 remplacements 🪑</strong> par match (améliorables). Surveillez les blessures ✚, les suspensions 🚫 et la barre d\'<strong>Endurance</strong> — reposez les joueurs sur le banc pour la récupérer.',
    de:'Bis zu <strong>2 Wechsel 🪑</strong> pro Spiel (verbesserbar). Achte auf Verletzungen ✚, Sperren 🚫 und die <strong>Ausdauer</strong>-Leiste — lass Spieler auf der Bank erholen.',
    it:'Fino a <strong>2 sostituzioni 🪑</strong> per partita (migliorabili). Tieni d\'occhio infortuni ✚, squalifiche 🚫 e la barra della <strong>Resistenza</strong> — fai riposare i giocatori in panchina per recuperarla.'
  },
  'howto.step4': {
    es:'La <strong>moral</strong> sube con goles/aciertos y baja con derrotas/fallos. El <strong>clima</strong> y las <strong>rachas 🔥</strong> también influyen en cada partido.',
    en:'<strong>Morale</strong> rises with goals/correct predictions and drops with defeats/misses. <strong>Weather</strong> and <strong>streaks 🔥</strong> also affect each match.',
    pt:'O <strong>moral</strong> sobe com gols/acertos e cai com derrotas/erros. O <strong>clima</strong> e as <strong>sequências 🔥</strong> também influenciam cada jogo.',
    fr:'Le <strong>moral</strong> monte avec les buts/bonnes prédictions et baisse avec les défaites/erreurs. La <strong>météo</strong> et les <strong>séries 🔥</strong> influencent aussi chaque match.',
    de:'Die <strong>Moral</strong> steigt mit Toren/richtigen Vorhersagen und sinkt mit Niederlagen/Fehlern. Das <strong>Wetter</strong> und <strong>Serien 🔥</strong> beeinflussen ebenfalls jedes Spiel.',
    it:'Il <strong>morale</strong> sale con gol/previsioni corrette e scende con sconfitte/errori. Il <strong>clima</strong> e le <strong>serie 🔥</strong> influenzano anche ogni partita.'
  },
  'howto.step5': {
    es:'Cada run puntúa de <strong>0 a 1000</strong>. Gana el Mundial para acercarte al máximo — tu mejor puntuación se guarda si estás registrado.',
    en:'Each run scores from <strong>0 to 1000</strong>. Win the World Cup to reach the maximum — your best score is saved if you are registered.',
    pt:'Cada tentativa pontua de <strong>0 a 1000</strong>. Vença o Mundial para chegar ao máximo — sua melhor pontuação fica salva se você estiver registrado.',
    fr:'Chaque tentative marque de <strong>0 à 1000</strong>. Remportez le Mondial pour atteindre le maximum — votre meilleur score est sauvegardé si vous êtes inscrit.',
    de:'Jeder Durchgang bewertet von <strong>0 bis 1000</strong>. Gewinne die WM, um das Maximum zu erreichen — deine beste Wertung wird gespeichert, wenn du registriert bist.',
    it:'Ogni tentativo totalizza da <strong>0 a 1000</strong>. Vinci il Mondiale per raggiungere il massimo — il tuo punteggio migliore viene salvato se sei registrato.'
  },

